function rescueFunds(
    address asset,
    uint256 amount,
    address destination
  ) public onlyOwner {
    if (asset == address(0)) {
      payable(destination).transfer(amount);
    } else {
      (bool success, ) = asset.call(
        abi.encodeWithSignature(
          "transfer(address,uint256)",
          destination,
          amount
        )
      );
      require(success, "Transfer failed");
    }
  }

